基本的には, C++版と同じになるように設計している. たとえば, Getting Started と等価なコードは以下のようになる. using AUTD3Sharp;
using AUTD3Sharp.Utils; namespace example
{ internal class Program { public static string GetIfname() { var adapters = SOEM.EnumerateAdapters(); var etherCATAdapters = adapters as EtherCATAdapter[] ?? adapters.ToArray(); foreach (var (adapter, index) in etherCATAdapters.Select((adapter, index) => (adapter, index))) Console.WriteLine("[{index}]: {adapter}"); Console.Write("Choose number: "); int i; while (!int.TryParse(Console.ReadLine(), out i)) { } return etherCATAdapters.ElementAt(i).Name; } public static void Main() { var autd = new Controller(); autd.AddDevice(Vector3d.Zero, Vector3d.Zero); var ifname = GetIfname(); var link = new SOEM(ifname, autd.NumDevices, 2); if (!autd.Open(link)) { Console.WriteLine(Controller.LastError); return; } autd.CheckAck = true; autd.Clear(); autd.Synchronize(); var firmList = autd.FirmwareInfoList().ToArray(); foreach (var (firm, index) in firmList.Select((firm, i) => (firm, i))) Console.WriteLine("AUTD {index}: {firm}"); var config = new SilencerConfig(); autd.Send(config); const double x = Controller.TransSpacing * ((Controller.NumTransInX - 1) / 2.0); const double y = Controller.TransSpacing * ((Controller.NumTransInY - 1) / 2.0); const double z = 150.0; var g = new Focus(new Vector3d(x, y, z)); var m = new Sine(150); autd.Send(m, g); Console.ReadKey(true); autd.Close(); } }
} より詳細なサンプルは autd3sharpのexample を参照されたい.

